import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "./Categories.css";

function Categories() {
  const navigate = useNavigate();
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [formData, setFormData] = useState({
    name: "",
    description: ""
  });
  const [message, setMessage] = useState("");
  const [messageType, setMessageType] = useState("");

  // Fetch categories dari backend
  useEffect(() => {
    fetchCategories();
  }, []);

  const fetchCategories = async () => {
    setLoading(true);
    try {
      const response = await fetch("http://localhost:5000/categories");
      const result = await response.json();
      if (result.success) {
        setCategories(result.data);
      }
    } catch (err) {
      console.error("Error fetching categories:", err);
      showMessage("Gagal mengambil kategori", "error");
    } finally {
      setLoading(false);
    }
  };

  const showMessage = (msg, type = "success") => {
    setMessage(msg);
    setMessageType(type);
    setTimeout(() => setMessage(""), 3000);
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.name.trim()) {
      showMessage("Nama kategori harus diisi", "error");
      return;
    }

    try {
      let response;
      if (editingId) {
        // Update
        response = await fetch(`http://localhost:5000/categories/${editingId}`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(formData)
        });
      } else {
        // Create
        response = await fetch("http://localhost:5000/categories", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(formData)
        });
      }

      const result = await response.json();

      if (result.success) {
        showMessage(result.message, "success");
        setFormData({ name: "", description: "" });
        setEditingId(null);
        setShowForm(false);
        fetchCategories();
      } else {
        showMessage(result.message, "error");
      }
    } catch (err) {
      console.error("Error:", err);
      showMessage("Terjadi kesalahan", "error");
    }
  };

  const handleEdit = (category) => {
    setFormData({
      name: category.name,
      description: category.description
    });
    setEditingId(category.id);
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Yakin ingin menghapus kategori ini?")) return;

    try {
      const response = await fetch(`http://localhost:5000/categories/${id}`, {
        method: "DELETE"
      });

      const result = await response.json();

      if (result.success) {
        showMessage("Kategori berhasil dihapus", "success");
        fetchCategories();
      } else {
        showMessage(result.message, "error");
      }
    } catch (err) {
      console.error("Error:", err);
      showMessage("Gagal menghapus kategori", "error");
    }
  };

  const handleCancel = () => {
    setFormData({ name: "", description: "" });
    setEditingId(null);
    setShowForm(false);
  };

  const filteredCategories = categories.filter(cat =>
    cat.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    cat.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleLogout = async () => {
    try {
      const token = localStorage.getItem("token");
      await fetch("http://localhost:5000/auth/logout", {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${token}`
        }
      });
    } catch (err) {
      console.error("Logout error:", err);
    }
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    navigate("/");
  };

  const handleBackToDashboard = () => {
    navigate("/dashboard");
  };

  return (
    <div className="categories-wrapper">
      <div className="categories-container">
        {/* Header */}
        <div className="categories-header">
          <div className="header-content">
            <h1>📂 Manajemen Kategori</h1>
            <p>Kelola kategori buku</p>
          </div>
          <div className="header-actions">
            <button
              className="btn btn-primary"
              onClick={() => {
                setShowForm(true);
                setEditingId(null);
                setFormData({ name: "", description: "" });
              }}
            >
              ➕ Tambah Kategori
            </button>
            <button
              className="btn btn-secondary"
              onClick={handleBackToDashboard}
              title="Kembali ke Dashboard"
            >
              🏠 Dashboard
            </button>
            <button className="btn btn-logout" onClick={handleLogout}>
              🚪 Logout
            </button>
          </div>
        </div>

        {/* Message */}
        {message && (
          <div className={`message message-${messageType}`}>
            {message}
          </div>
        )}

        {/* Form */}
        {showForm && (
          <div className="form-card">
            <h3>{editingId ? "✏️ Edit Kategori" : "➕ Tambah Kategori Baru"}</h3>
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label htmlFor="name">Nama Kategori *</label>
                <input
                  type="text"
                  id="name"
                  name="name"
                  value={formData.name}
                  onChange={handleInputChange}
                  placeholder="Contoh: Cerita Rakyat"
                  required
                />
              </div>

              <div className="form-group">
                <label htmlFor="description">Deskripsi</label>
                <textarea
                  id="description"
                  name="description"
                  value={formData.description}
                  onChange={handleInputChange}
                  placeholder="Deskripsi kategori..."
                  rows="3"
                />
              </div>

              <div className="form-actions">
                <button type="submit" className="btn btn-success">
                  {editingId ? "💾 Update" : "💾 Simpan"}
                </button>
                <button
                  type="button"
                  className="btn btn-secondary"
                  onClick={handleCancel}
                >
                  ❌ Batal
                </button>
              </div>
            </form>
          </div>
        )}

        {/* Search */}
        <div className="search-section">
          <input
            type="text"
            className="search-box"
            placeholder="🔍 Cari kategori..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <span className="result-count">
            Menampilkan {filteredCategories.length} dari {categories.length} kategori
          </span>
        </div>

        {/* Table */}
        {loading ? (
          <div className="loading">
            <div className="spinner"></div>
            <p>Memuat kategori...</p>
          </div>
        ) : filteredCategories.length > 0 ? (
          <div className="table-wrapper">
            <table className="categories-table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Nama Kategori</th>
                  <th>Deskripsi</th>
                  <th>Aksi</th>
                </tr>
              </thead>
              <tbody>
                {filteredCategories.map((category) => (
                  <tr key={category.id} className="table-row">
                    <td className="col-id">{category.id}</td>
                    <td className="col-name">
                      <span className="badge">{category.name}</span>
                    </td>
                    <td className="col-description">{category.description}</td>
                    <td className="col-action">
                      <button
                        className="btn btn-sm btn-edit"
                        onClick={() => handleEdit(category)}
                        title="Edit"
                      >
                        ✏️
                      </button>
                      <button
                        className="btn btn-sm btn-delete"
                        onClick={() => handleDelete(category.id)}
                        title="Hapus"
                      >
                        🗑️
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="no-data">
            <p>📭 Tidak ada kategori</p>
          </div>
        )}
      </div>
    </div>
  );
}

export default Categories;
